# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from PIL import Image
import io
import os

s3 = boto3.client('s3')
ec2 = boto3.client('ec2')

def create_screenshot(url, width=300, height=150):
    options = Options()
    options.add_argument('--headless')
    driver = webdriver.Chrome(options=options)

    driver.get(url)
    image_data = driver.get_screenshot_as_png()

    img = Image.open(io.BytesIO(image_data))
    img = img.crop((0, 100, width, height))  # Remove header
    img.thumbnail((width, height))

    byte_array = io.BytesIO()
    img.save(byte_array, 'PNG')
    screenshot_binary = byte_array.getvalue()

    driver.quit()

    return screenshot_binary

def upload_screenshot(url, screenshot_binary):
    bucket_name = os.environ['S3_BUCKET_NAME']
    s3.put_object(Body=screenshot_binary,
                  Bucket=bucket_name,
                  Key=f"screenshots/{url}.png")

def lambda_handler(event, context):
    url = event['url']
    width = int(os.environ.get('WIDTH', 300))
    height = int(os.environ.get('HEIGHT', 150))

    screenshot_binary = create_screenshot(url, width, height)
    upload_screenshot(url, screenshot_binary)

    return {
        'statusCode': 200,
        'statusMessage': 'OK'
    }